```class Solution {
public:
    int removePalindromeSub(string s) {
        int a = 0, b = 0;
        for (char c : s) {
            if (c == 'a') a++;
            else b++;
        }
        if (a == 0 || b == 0) return 1;
        return 2;
    }
};
```
